atom-text-editor[mini] {
  line-height: @component-line-height;
  max-height: @component-line-height + 2; // +2 for borders

  overflow: auto;
}
atom-text-editor,
editor {
  background-color: @app-background-color;
}

atom-text-editor,
.tile,:host{
  background-color:  transparent ;
}
atom-text-editor,
atom-text-editor.editor {
  .scroll-view {
  background-color:   @app-background-color !important ;

  }
  .gutter {
  background-color:   @app-background-color !important ;

  }
}




atom-text-editor[mini] {
  font-size: @ui-input-size;
  line-height: @ui-line-height;
  max-height: none;
  padding-left: 0;
  border-radius: @component-border-radius;
  color: @text-color-highlight;
  border: 1px solid @input-border-color;
  background-color: @input-background-color;
  padding-left: @ui-padding/2;

  &,
  &.editor {
    .placeholder-text {
      color: @text-color-subtle;
    }
    .selection .region {
      background-color: @input-selection-color;
    }
    .cursor {
      border-color: @base-accent-color;
      border-width: 2px;
    }
  }

  &.is-focused,
  &.is-focused.editor {
    .focus();
    background-color: @input-background-color-focus;
    .selection .region {
      background-color: @input-selection-color-focus;
    }
  }
}

// Grabbed from legacy docs theme
.gutter pre {
  color: #ddd;
}

pre {
  color: @color-darkest;

  .function .keyword,
  .constant {
    color: #0092db
	}

  .keyword,
  .attribute {
    color: #e96900
	}

  .number,
  .literal {
    color: #AE81FF
	}

  .tag,
  .tag .title,
  .change,
  .winutils,
  .flow,
  .lisp .title,
  .clojure .built_in,
  .nginx .title,
  .tex .special {
    color: #2973b7
	}

  .class .title {
    color: #4077BF
	}

  .symbol,
  .symbol .string,
  .value,
  .regexp {
    color: #90a959
	}

  .title {
    color: #A6E22E
	}

  .tag .value,
  .string,
  .subst,
  .haskell .type,
  .preprocessor,
  .ruby .class .parent,
  .built_in,
  .sql .aggregate,
  .django .template_tag,
  .django .variable,
  .smalltalk .class,
  .javadoc,
  .django .filter .argument,
  .smalltalk .localvars,
  .smalltalk .array,
  .attr_selector,
  .pseudo,
  .addition,
  .stream,
  .envvar,
  .apache .tag,
  .apache .cbracket,
  .tex .command,
  .prompt {
    color: @color-primary;
	}

  .comment,
  .java .annotation,
  .python .decorator,
  .template_comment,
  .pi,
  .doctype,
  .deletion,
  .shebang,
  .apache .sqbracket,
  .tex .formula {
    color: @color-mediumdark;
	}

  .coffeescript .javascript,
  .javascript .xml,
  .tex .formula,
  .xml .javascript,
  .xml .vbscript,
  .xml .css,
  .xml .cdata {
    opacity: 0.5
	}
}

